op: none; width: 23pt;">　</td><td class="xl7030099" width="70" style="border-top: none; width: 53pt;">　</td><td class="xl7030099" width="70" style="border-top: none; width: 53pt;">　</td><td class="xl7030099" width="63" style="border-top: none; width: 47pt;">　</td><td class="xl7030099" width="63" style="border-top: none; width: 47pt;">　</td><td class="xl7030099" width="63" style="border-top: none; width: 47pt;">　</td><td class="xl7030099" width="63" style="border-top: none; width: 47pt;">　</td><td class="xl7030099" width="116" style="border-top: none; width: 87pt;">　</td><td class="xl7130099" style="border-top: none;">　</td><td class="xl6430099"></td></tr><tr height="126" style="height: 94.8pt;"><td height="126" class="xl6430099" style="height: 94.8pt;"></td><td class="xl7230099">　</td><td colspan="8" class="xl7330099" width="539" style="width: 404pt;">다음의 예시는 미배당 이익에
  대하여 50%의 높은 세율로 법인세를 납부하고 이익이 배당될 때 환급가능한 경우 당기법인세 자산과 부채 및 이연법인세 자산과 부채의 측정에
  대하여 다루고 있다. 배당된 이익에 대한 법인세율은 35%이다. 20X1년 12월 31일 보고기간말 현재 보고기간 후 결의된 배당금을
  부채로 인식하지 않았다. 그 결과 20X1년에 인식된 배당은 없다.<br>
    20X1년의 과세대상수익은 100,000원이며, 순 가산할 일시적차이는 40,000원이다.</td><td class="xl7430099">　</td><td class="xl6430099"></td></tr><tr height="6" style="height: 4.95pt;"><td height="6" class="xl6430099" style="height: 4.95pt;"></td><td class="xl7230099">　</td><td class="xl7530099"></td><td class="xl7330099" width="70" style="width: 53pt;"></td><td class="xl7330099" width="70" style="width: 53pt;"></td><td class="xl7330099" width="63" style="width: 47pt;"></td><td class="xl7330099" width="63" style="width: 47pt;"></td><td class="xl7330099" width="63" style="width: 47pt;"></td><td class="xl7330099" width="63" style="width: 47pt;"></td><td class="xl7330099" width="116" style="width: 87pt;"></td><td class="xl7430099">　</td><td class="xl6430099"></td></tr><tr height="86" style="height: 64.8pt;"><td height="86" class="xl6430099" style="height: 64.8pt;"></td><td class="xl7230099">　</td><td colspan="8" class="xl7630099" width="539" style="width: 404pt;">기업은 당기법인세부채와
  당기법인세비용으로 50,000원을 인식하며, 미래 배당의 결과 잠재적으로 환급가능한 금액을 자산으로 인식하지 아니한다. 또한 미배당이익에
  적용되는 세율에 근거하여 당해 자산과 부채의 장부금액을 회수하거나 결제할 때 지급할 법인세를 나타내는 20,000원(40,000원의
